            onClick={() => setMode('conversational')}
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${mode === 'conversational' ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-slate-400 hover:text-white'}`}
          >
            <ChatBubbleBottomCenterTextIcon className="w-4 h-4" /> Quick Pitch
