            </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="md:col-span-2 space-y-2">
                <label className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">
                  <BoltIcon className="w-3 h-3 text-blue-400" /> Core Workload Description
                </label>
                <input
                  value={brief.workload}
                  onChange={(e) => setBrief({...brief, workload: e.target.value})}
                  placeholder="What is this application doing?"
                  className="w-full bg-black/20 border border-white/10 rounded-xl px-5 py-4 text-white placeholder-slate-600 focus:outline-none focus:ring-2 focus:ring-blue-500/30 transition-all"
                />
