              <div className="space-y-2">
                <label className="flex items-center gap-2 text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">
                  <DocumentTextIcon className="w-3 h-3 text-indigo-400" /> Traffic & Scale
                </label>
                <input
