      dangerouslySetInnerHTML={{ __html: svg || '<div class="animate-pulse flex space-y-4 flex-col items-center"><div class="rounded-full bg-slate-800 h-10 w-10"></div><div class="h-2 bg-slate-800 rounded w-32"></div></div>' }}
