            {loading ? (
              <ArrowPathIcon className="w-4 h-4 animate-spin" />
            ) : isOpen ? (
              <>Hide Architect Review <BoltIcon className="w-4 h-4" /></>
            ) : (
              <>Ask Architect: Analyze Jargon & Patterns <QuestionMarkCircleIcon className="w-4 h-4" /></>
