import React, { useState } from 'react';
import { 
  AcademicCapIcon, 
  ArrowPathIcon, 
  CheckCircleIcon, 
  XCircleIcon, 
  LightBulbIcon, 
  ChevronRightIcon,
  FireIcon
} from '@heroicons/react/24/solid';
import { generateExamQuestion } from '../services/gemini';
import { ExamQuestion } from '../types';

const ExamSimulator: React.FC = () => {
  const [question, setQuestion] = useState<ExamQuestion | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [score, setScore] = useState({ correct: 0, total: 0 });

  const topics = [
    "High Availability & DR",
    "Serverless Decoupling",
    "IAM Governance & Organizations",
    "Database Selection & Scaling",
    "Cost Optimization & FinOps",
    "Hybrid Networking & DX"
  ];

  const handleStartQuestion = async (topic: string) => {
    setLoading(true);
    setQuestion(null);
    setSelectedOption(null);
    setShowExplanation(false);
    try {
      const q = await generateExamQuestion(topic);
      setQuestion(q);
    } catch (err) {
      alert("Failed to reach the examiner.");
    } finally {
      setLoading(false);
    }
  };

  const handleOptionSelect = (optionId: string) => {
    if (selectedOption) return;
    setSelectedOption(optionId);
    setShowExplanation(true);

    const isCorrect = question?.options.find(o => o.id === optionId)?.isCorrect;
    if (isCorrect) {
      setScore(prev => ({ ...prev, correct: prev.correct + 1 }));
    }
    setScore(prev => ({ ...prev, total: prev.total + 1 }));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 pb-20 animate-fadeIn">
      {!question && !loading && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="md:col-span-2 glass p-10 rounded-[3rem] border border-orange-500/20 bg-orange-500/[0.02] text-center">
            <FireIcon className="w-16 h-16 text-orange-500 mx-auto mb-6" />
            <h2 className="text-3xl font-black text-white mb-4">Certification "Hot Seat"</h2>
            <p className="text-slate-400 max-w-xl mx-auto mb-10">
              Select a domain to challenge your architectural instincts. Gemini will generate a real-world scenario question that mimics the SAA-C03 and SAP-C02 professional exams.
            </p>
            <div className="flex flex-wrap justify-center gap-4">
              {topics.map(topic => (
                <button 
                  key={topic}
                  onClick={() => handleStartQuestion(topic)}
                  className="px-6 py-3 bg-white/5 border border-white/10 hover:bg-orange-600/20 hover:border-orange-500/40 rounded-2xl text-sm font-bold text-slate-300 transition-all"
                >
                  {topic}
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {loading && (
        <div className="flex flex-col items-center justify-center py-32 space-y-6">
          <ArrowPathIcon className="w-16 h-16 text-blue-500 animate-spin" />
          <p className="text-slate-400 font-black uppercase tracking-widest text-xs animate-pulse">Generating Scenario...</p>
        </div>
      )}

      {question && (
        <div className="space-y-8 animate-fadeIn">
          <div className="flex justify-between items-center mb-4">
            <div className="flex items-center gap-3">
              <span className="px-3 py-1 bg-blue-500/10 text-blue-400 border border-blue-500/20 rounded-full text-[10px] font-black uppercase tracking-widest">
                {question.pillar}
              </span>
            </div>
            <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
              Readiness: {score.total > 0 ? Math.round((score.correct / score.total) * 100) : 0}% ({score.correct}/{score.total})
            </div>
          </div>

          <div className="glass p-12 rounded-[3.5rem] border border-white/5 space-y-10">
            <h3 className="text-2xl font-bold text-white leading-relaxed">
              {question.scenario}
            </h3>

            <div className="grid grid-cols-1 gap-4">
              {question.options.map(option => {
                const isSelected = selectedOption === option.id;
                const isCorrect = option.isCorrect;
                let bgClass = "bg-white/5 border-white/5 hover:bg-white/10";

                if (selectedOption) {
                  if (isCorrect) bgClass = "bg-emerald-500/10 border-emerald-500/40 text-emerald-400 ring-2 ring-emerald-500/20";
                  else if (isSelected && !isCorrect) bgClass = "bg-rose-500/10 border-rose-500/40 text-rose-400 ring-2 ring-rose-500/20";
                }

                return (
                  <button
                    key={option.id}
                    disabled={!!selectedOption}
                    onClick={() => handleOptionSelect(option.id)}
                    className={`p-6 rounded-2xl border text-left transition-all relative overflow-hidden group ${bgClass}`}
                  >
                    <div className="flex items-start gap-4">
                      <div className="w-6 h-6 rounded-full border border-current flex items-center justify-center shrink-0 mt-0.5">
                        {selectedOption && isCorrect ? <CheckCircleIcon className="w-5 h-5" /> : 
                         selectedOption && isSelected && !isCorrect ? <XCircleIcon className="w-5 h-5" /> : 
                         <span className="text-[10px] font-black uppercase">{option.id}</span>}
                      </div>
                      <span className="text-sm font-medium leading-relaxed">{option.text}</span>
                    </div>
                  </button>
                );
              })}
            </div>

            {showExplanation && (
              <div className="mt-12 pt-12 border-t border-white/5 animate-fadeIn">
                <div className="flex items-center gap-3 mb-6">
                  <LightBulbIcon className="w-6 h-6 text-yellow-500" />
                  <h4 className="text-xs font-black text-yellow-500 uppercase tracking-widest">Architectural Justification</h4>
                </div>
                <div className="p-8 bg-white/5 rounded-[2.5rem] border border-white/5 space-y-6">
                  <p className="text-slate-300 leading-relaxed italic">
                    {question.explanation}
                  </p>
                  <button 
                    onClick={() => handleStartQuestion(question.pillar)}
                    className="flex items-center gap-2 text-[10px] font-black text-blue-400 hover:text-white uppercase tracking-[0.3em] transition-colors"
                  >
                    Next Challenge <ChevronRightIcon className="w-4 h-4" />
                  </button>
                </div>
              </div>
            )}
          </div>

          <button 
            onClick={() => setQuestion(null)}
            className="text-xs font-black text-slate-500 uppercase tracking-widest hover:text-white transition-colors"
          >
            Quit Session
          </button>
        </div>
      )}
    </div>
  );
};

