import { GoogleGenAI, Type } from "@google/genai";
import { ScenarioMatch, ArchitectureReview, StepExplanation, ExamQuestion } from "../types";

export const generateExamQuestion = async (topic: string): Promise<ExamQuestion> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Generate a high-level AWS Solutions Architect professional-level scenario exam question about: "${topic}". 

    The question should focus on "The most cost-effective AND resilient" choice.
    Provide 4 options. Only one must be correct.
    Provide a detailed 'explanation' that references the AWS Well-Architected Framework and 2026 best practices.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          scenario: { type: Type.STRING },
          pillar: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                text: { type: Type.STRING },
                isCorrect: { type: Type.BOOLEAN }
              },
              required: ["id", "text", "isCorrect"]
            }
          },
          explanation: { type: Type.STRING }
        },
        required: ["scenario", "options", "explanation", "pillar"]
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}");
  } catch (e) {
    throw new Error("Failed to generate exam question.");
  }
};

export const matchAWSService = async (scenario: string): Promise<ScenarioMatch> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
