import { ScenarioMatch, ArchitectureReview, StepExplanation, ExamQuestion } from "../types";

export const generateExamQuestion = async (topic: string): Promise<ExamQuestion> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Generate a high-level AWS Solutions Architect professional-level scenario exam question about: "${topic}". 

    The question should focus on "The most cost-effective AND resilient" choice, as per 2026-era best practices.
    Provide 4 distinct options. Only one must be correctly satisfying all constraints.
    Provide a detailed 'explanation' that references the AWS Well-Architected Framework.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          scenario: { type: Type.STRING },
          pillar: { type: Type.STRING },
          options: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                id: { type: Type.STRING },
                text: { type: Type.STRING },
                isCorrect: { type: Type.BOOLEAN }
              },
              required: ["id", "text", "isCorrect"]
            }
          },
          explanation: { type: Type.STRING }
        },
        required: ["scenario", "options", "explanation", "pillar"]
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}");
  } catch (e) {
    throw new Error("Failed to generate exam question.");
  }
};

export const matchAWSService = async (scenario: string): Promise<ScenarioMatch> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `You are a Principal AWS Solutions Architect. For the following scenario, provide a Board-Level architectural design: "${scenario}". 

    Requirements:
    1. A clear 'recommendedService'.
    2. A deep 'justification' explaining the 2026-era benefits.
    3. A multi-phase 'implementationSteps' list. 
    4. A Mermaid.js diagram representing the service flow using 'graph TD'.
    5. 'alternatives' for trade-off discussions.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          recommendedService: { type: Type.STRING },
          justification: { type: Type.STRING },
          implementationSteps: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                phase: { type: Type.STRING },
                details: { type: Type.STRING }
              },
              required: ["phase", "details"]
            }
          },
          mermaidDiagram: { type: Type.STRING },
          alternatives: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["recommendedService", "justification", "implementationSteps", "mermaidDiagram"]
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}");
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Architecture generation failed.");
  }
};

export const explainStepDetail = async (phase: string, details: string, context: string): Promise<StepExplanation> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Architect Context: ${context} | Phase: ${phase} | Details: ${details}`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          explanation: { type: Type.STRING },
          codeSnippets: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                language: { type: Type.STRING },
                code: { type: Type.STRING }
              },
              required: ["title", "language", "code"]
            }
          },
          keyTerms: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: { term: { type: Type.STRING }, definition: { type: Type.STRING } },
              required: ["term", "definition"]
            }
          },
          documentationLinks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: { title: { type: Type.STRING }, url: { type: Type.STRING } },
              required: ["title", "url"]
            }
          }
        },
        required: ["explanation", "keyTerms", "documentationLinks", "codeSnippets"]
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}");
  } catch (e) {
    throw new Error("Could not fetch expert explanation.");
  }
};

export const reviewArchitecture = async (description: string): Promise<ArchitectureReview> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Review the following AWS architecture against the 6 Pillars of the Well-Architected Framework: "${description}".`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          pillarRatings: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                pillar: { type: Type.STRING },
                rating: { type: Type.NUMBER },
                feedback: { type: Type.STRING }
              },
              required: ["pillar", "rating", "feedback"]
            }
          },
          criticalFixes: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          costOptimizationScore: { type: Type.STRING }
        },
        required: ["pillarRatings", "criticalFixes", "costOptimizationScore"]
      }
    }
  });

  try {
    return JSON.parse(response.text || "{}");
  } catch (e) {
    throw new Error("Failed to parse architect review");
  }
};

import React, { useState } from 'react';
import { 
  ArrowPathIcon, 
  CheckCircleIcon, 
  XCircleIcon, 
  LightBulbIcon, 
  ChevronRightIcon,
  FireIcon
} from '@heroicons/react/24/solid';
import { generateExamQuestion } from '../services/gemini';
import { ExamQuestion } from '../types';

const ExamSimulator: React.FC = () => {
  const [question, setQuestion] = useState<ExamQuestion | null>(null);
  const [loading, setLoading] = useState(false);
  const [selectedOption, setSelectedOption] = useState<string | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [score, setScore] = useState({ correct: 0, total: 0 });

  const topics = [
    "High Availability & DR",
    "Serverless Decoupling",
    "IAM Governance & Organizations",
    "Database Selection & Scaling",
    "Cost Optimization & FinOps",
    "Hybrid Networking & DX"
  ];

  const handleStartQuestion = async (topic: string) => {
    setLoading(true);
    setQuestion(null);
    setSelectedOption(null);
    setShowExplanation(false);
    try {
      const q = await generateExamQuestion(topic);
      setQuestion(q);
    } catch (err) {
      alert("Failed to reach the examiner.");
    } finally {
      setLoading(false);
    }
  };

  const handleOptionSelect = (optionId: string) => {
    if (selectedOption) return;
    setSelectedOption(optionId);
    setShowExplanation(true);

    const isCorrect = question?.options.find(o => o.id === optionId)?.isCorrect;
    if (isCorrect) {
      setScore(prev => ({ ...prev, correct: prev.correct + 1 }));
    }
    setScore(prev => ({ ...prev, total: prev.total + 1 }));
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 pb-20 animate-fadeIn">
      {!question && !loading && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="md:col-span-2 glass p-10 rounded-[3rem] border border-orange-500/20 bg-orange-500/[0.02] text-center">
            <FireIcon className="w-16 h-16 text-orange-500 mx-auto mb-6" />
            <h2 className="text-3xl font-black text-white mb-4 tracking-tighter uppercase">Certification "The Hot Seat"</h2>
            <p className="text-slate-400 max-w-xl mx-auto mb-10 font-light text-lg">
              Challenge your architectural instincts. Gemini proctors a high-fidelity scenario question that mimics the rigors of SAA-C03 and SAP-C02 professional exams.
            </p>
            <div className="flex flex-wrap justify-center gap-4">
              {topics.map(topic => (
                <button 
                  key={topic}
                  onClick={() => handleStartQuestion(topic)}
                  className="px-6 py-3 bg-white/5 border border-white/10 hover:bg-orange-600/20 hover:border-orange-500/40 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-300 transition-all"
                >
                  {topic}
                </button>
              ))}
            </div>
          </div>
        </div>
      )}

      {loading && (
        <div className="flex flex-col items-center justify-center py-32 space-y-6">
          <ArrowPathIcon className="w-16 h-16 text-orange-500 animate-spin" />
          <p className="text-slate-400 font-black uppercase tracking-[0.3em] text-[10px] animate-pulse">Initializing Proctoring Agent...</p>
        </div>
      )}

      {question && (
        <div className="space-y-8 animate-fadeIn">
          <div className="flex justify-between items-center mb-4">
            <div className="flex items-center gap-3">
              <span className="px-3 py-1 bg-blue-500/10 text-blue-400 border border-blue-500/20 rounded-full text-[10px] font-black uppercase tracking-widest">
                {question.pillar}
              </span>
            </div>
            <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest bg-white/5 px-4 py-1.5 rounded-full border border-white/5">
              Readiness: {score.total > 0 ? Math.round((score.correct / score.total) * 100) : 0}% ({score.correct}/{score.total})
            </div>
          </div>

          <div className="glass p-12 rounded-[3.5rem] border border-white/5 space-y-12 relative overflow-hidden">
            <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-orange-500 to-transparent" />
            <h3 className="text-2xl font-bold text-white leading-relaxed">
              {question.scenario}
            </h3>

            <div className="grid grid-cols-1 gap-4">
              {question.options.map(option => {
                const isSelected = selectedOption === option.id;
                const isCorrect = option.isCorrect;
                let bgClass = "bg-white/5 border-white/5 hover:bg-white/10 hover:border-white/20";

                if (selectedOption) {
                  if (isCorrect) bgClass = "bg-emerald-500/10 border-emerald-500/40 text-emerald-400 ring-2 ring-emerald-500/20";
                  else if (isSelected && !isCorrect) bgClass = "bg-rose-500/10 border-rose-500/40 text-rose-400 ring-2 ring-rose-500/20";
                }

                return (
                  <button
                    key={option.id}
                    disabled={!!selectedOption}
                    onClick={() => handleOptionSelect(option.id)}
                    className={`p-6 rounded-2xl border text-left transition-all relative overflow-hidden group ${bgClass}`}
                  >
                    <div className="flex items-start gap-5">
                      <div className="w-6 h-6 rounded-full border border-current flex items-center justify-center shrink-0 mt-0.5 text-[10px] font-black uppercase">
                        {selectedOption && isCorrect ? <CheckCircleIcon className="w-5 h-5" /> : 
                         selectedOption && isSelected && !isCorrect ? <XCircleIcon className="w-5 h-5" /> : 
                         <span>{option.id}</span>}
                      </div>
                      <span className="text-sm font-medium leading-relaxed">{option.text}</span>
                    </div>
                  </button>
                );
              })}
            </div>

            {showExplanation && (
              <div className="mt-12 pt-12 border-t border-white/5 animate-fadeIn">
                <div className="flex items-center gap-3 mb-6">
                  <LightBulbIcon className="w-6 h-6 text-yellow-500" />
                  <h4 className="text-[10px] font-black text-yellow-500 uppercase tracking-[0.4em]">Architectural Justification</h4>
                </div>
                <div className="p-8 bg-white/5 rounded-[2.5rem] border border-white/5 space-y-8">
                  <p className="text-slate-300 leading-relaxed italic text-lg font-light">
                    {question.explanation}
                  </p>
                  <button 
                    onClick={() => handleStartQuestion(question.pillar)}
                    className="flex items-center gap-3 text-[10px] font-black text-blue-400 hover:text-white uppercase tracking-[0.3em] transition-colors"
                  >
                    Next Challenge <ChevronRightIcon className="w-4 h-4" />
                  </button>
                </div>
              </div>
            )}
          </div>

          <div className="flex justify-center">
            <button 
              onClick={() => setQuestion(null)}
              className="text-[10px] font-black text-slate-500 uppercase tracking-widest hover:text-white transition-colors border-b border-transparent hover:border-white/20 pb-1"
            >
              Exit Proctored Session
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default ExamSimulator;

