            <p className="text-xs text-slate-400 leading-relaxed">• {phase.focus}</p>
          </button>
        ))}
      </div>

      <section className="pt-16 border-t border-white/10">
        <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-12">
          <div>
            <h3 className="text-3xl font-black text-white uppercase tracking-tighter">Roadmap Validation</h3>
            <p className="text-slate-400">Put your knowledge to the test with real-time AI scenario analysis based on your 30-day journey.</p>
          </div>
          <button 
            onClick={() => setShowSimulator(!showSimulator)}
            className={`px-10 py-4 rounded-2xl font-black text-xs uppercase tracking-widest transition-all flex items-center gap-3 shadow-xl 
            ${showSimulator ? 'bg-white/10 text-white border border-white/20' : 'bg-orange-600 hover:bg-orange-500 text-white shadow-orange-600/20'}`}
          >
            {showSimulator ? 'Close Exam Sim' : 'Activate The Hot Seat'} <FireIcon className="w-5 h-5" />
          </button>
        </div>

        {showSimulator && (
          <div className="animate-fadeIn">
            <ExamSimulator />
          </div>
        )}
      </section>

      <div className="glass p-12 rounded-[3rem] border border-blue-500/20 flex flex-col md:flex-row items-center gap-10">
        <div className="flex-1">
          <h3 className="text-2xl font-bold text-white mb-4">Certification Strategy (SAA-C03)</h3>
          <p className="text-slate-400 leading-relaxed">
            Combine this roadmap with active-recall training. Focus 70% of your time on Compute, Networking, and Storage as they represent the majority of exam weight.
          </p>
        </div>
        <button className="px-10 py-4 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-2xl font-bold shadow-xl shadow-blue-500/20 hover:scale-105 transition-transform">
          Get Study Pack
        </button>
      </div>
    </div>
  );
};

export default RoadmapSection;
